var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님, 저기 보십시오! 구원자님이십니다!","JPN":"隊長、あちらを見てください！　救世主様です！","ENG":"Look, Captain! The Savior is coming!","TWN":"隊長，快看那邊！是救贖者大人！"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"오셨군요. 방금 막 보초들에게 혼자 가셨다는 말을 전해 들은 참이었습니다.","JPN":"戻られたんですね。先ほど見張りから一人でどこかへ向かわれたという話を聞いたところでした。","ENG":"You have arrived. I have just heard from the guards that you went alone.","TWN":"您來了。我剛聽站崗的人說您一個人走了。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 정식으로 보고했다간 다른 분들도 따라오셔야 할 테니까요.","JPN":"はい、正式に報告したら、他の皆さんもついてこないといけなくなりますから。","ENG":"Yes. If I were to make an official report, the others would have to follow.","TWN":"沒錯，因為正式報告的話，各位也都會跟過來吧。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"걱정하게 만들었다면 죄송합니다.","JPN":"心配かけて申し訳ありません。","ENG":"I apologize if I made you worry.","TWN":"抱歉，讓大家擔心了。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"천만에요. 아무 일 없으셔서 다행입니다.","JPN":"いいえ。ご無事で何よりです。","ENG":"No need. I am only glad that you are back, safe and sound.","TWN":"哪裡的話，您沒事就好。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"하지만 위험을 무릅쓰진 말아 주십시오. 구원자님께서는 저희의 희망이시니까요.","JPN":"しかしあまり危険を顧みないことはおやめください。救世主様は我々の希望ですから。","ENG":"Alas, I will have to ask you to be careful next time. You are our only hope.","TWN":"不過請您不要冒險，因為救贖者大人您是我們的希望。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니. 군법에 어긋나는 행동을 저질렀다는 사실 자체가 중요해.","JPN":"いや、今回は軍法に背いたということ自体が問題だ。","ENG":"No, the fact that he disobeyed the rules needs to be discussed.","TWN":"不，做出違反軍法的行為這件事本身也很重要。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌. 기다리고 있었어?","JPN":"アレン、待っていたの？","ENG":"Allen. Were you waiting?","TWN":"艾倫，你是在等我嗎？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당연하지. 전력의 핵심이 사라졌는데.","JPN":"当たり前だ。最も重要な戦力がどこかにいなくなったんだ。","ENG":"Of course I was. You’re the pillar of our forces.","TWN":"作為戰鬥力核心的人員失蹤了，我當然會如此。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"죄송합니다, 단장님! 저희 대응이 늦어져서 그만……!","JPN":"申し訳ありません団長！　対応が遅くなってしまったせいで……！","ENG":"I'm sorry, Commander! Our response was too late...!","TWN":"對不起，團長！因為我們反應慢了……！"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"책임을 물을 생각은 없다. 원인은 일탈을 벌인 구원자가 제공했으니까.","JPN":"責任を問うつもりはない。原因は逸脱を犯した救世主本人だからな。","ENG":"I'm not here to make anyone else responsible, since it was the Savior who left his post without notice.","TWN":"我不想追究你的責任。相反，這是擅自離隊的救贖者所造成的結果。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"얘기를 나눠야 하는데, 잠시 병사들을 데리고 자리를 비켜 주겠나?","JPN":"少し話し合いがしたいのだが、しばらく兵士たちを連れて、席を外してくれないか？","ENG":"I need a word with him in private. Will all of you excuse us for a moment?","TWN":"我要和他談談，你能帶著士兵先離開嗎？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예, 알겠습니다!","JPN":"はい、かしこまりました！","ENG":"Yes, sir!","TWN":"是，明白！"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"내일이 출정식이다. 설마 잊은 건 아니겠지?","JPN":"明日は出征式だ。まさか忘れたわけではないだろうな？","ENG":"The ceremony of war is going to be held tomorrow. Or did you already forget that?","TWN":"明天是出征儀式。你不會忘了吧？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"물론이지. 기억하고 있어.","JPN":"もちろん。覚えているよ。","ENG":"Of course not. I remember.","TWN":"我當然記得。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어젯밤엔 루크레시아가 말해 줘서 전하께서 서실 연단도 보러 갔거든. 정말 멋지더라.","JPN":"昨夜はルクレシアが言ってくれて、殿下がお立ちになる演壇も見てきたんだ。すごかったよ。","ENG":"I even went to see the podium that His Highness is going to stand on yesterday. Lucrecia told me about it. It looked great.","TWN":"昨晚露可蕾西亞告訴我了，我還特意去看了殿下要站的講台。很是雄偉。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그리고 가서 전하 얘기만 실컷 했고?","JPN":"それで、そこでルクレシアに殿下の話ばかりして終わったのか？","ENG":"I'm guessing you just talked about His Highness to Lucrecia the whole time.","TWN":"你一直在和露可蕾西亞聊殿下的事？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"응. 무슨 문제라도 있어?","JPN":"うん、何か問題でも？","ENG":"Yes. Is there a problem with that?","TWN":"嗯，有什麼問題嗎？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아주 많은 문제가 있지. 루크레시아도 고민이 많겠군.","JPN":"ああ問題大ありだ。ルクレシアの心労がうかがえるな。","ENG":"There are a lot of problems with that. Lucrecia must be in distress.","TWN":"當然……露可蕾西亞大概會很不開心吧。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아무튼, 마왕은 이제까지 상대했던 적들과 격이 달라.","JPN":"とにかく、魔王はこれまでの相手とは格が違う。","ENG":"Anyway, the Demon Lord is nothing like the ones we've come across so far.","TWN":"總之，魔王與以往的對手不同。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"단독 행동은 절대 안 돼. 이번만큼은 철저하게 내 지휘에 따라 줘야 한다.","JPN":"単独行動は許されない。今回ばかりは徹底的に私の指揮に従ってもらう。","ENG":"No more going off on your own. This time, you follow my orders only.","TWN":"你絕對不能單獨行動。這次必須嚴格聽從我的指揮。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알겠어. 알렌의 지휘는 믿을 수 있으니까.","JPN":"わかったよ。アレンの指揮は信用できるから。","ENG":"Okay. You know I trust you, Allen.","TWN":"好，因為艾倫的指揮一直都很可靠的嘛。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하나 너나, 그렇게 말해 놓고 마음대로 행동한 적이 한두 번이었어야지.","JPN":"殿下も君も、そう言うだけ言って、勝手に行動した例が多すぎる。","ENG":"I also know you and His Highness always somehow fail to do so.","TWN":"不管是殿下還是你，都經常這樣口頭上答應，之後卻還是隨意行動。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오, 알렌 경. 상당히 대범해지지 않았나. 주둔지에서 황족의 험담을 늘어 놓다니.","JPN":"ほう、アレン。いつからそんなに大胆になったんだ？　駐屯地で皇族の悪口を言うとは。","ENG":"You've become bold, Sir Allen. Talking about royalty like that.","TWN":"呵呵，很大膽嘛，艾倫卿。竟然在背地裡說皇室的壞話。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"황족을 기망한 죄는 사형입니다, 전하.","JPN":"皇族を侮辱した罪は死刑に値します。殿下。","ENG":"Deceiving against the crown is punishable by death, sir.","TWN":"欺罔皇室是要執行死刑嗎，殿下？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"사실 그대로 말했을 뿐입니다.","JPN":"事実を言ったまでです。","ENG":"I was merely speaking the truth.","TWN":"我只是實話實話而已。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금도 막사에 계시면 제가 처리하고 오겠다고 한 지가 5분도 안 지났습니다.","JPN":"今も、兵舎にいてくだされば私が対応して参りますと申し上げてから5分も経っていません。","ENG":"Even now, it's been less than 5 minutes since I told you to stay in the barracks, Your Highness. I said I will take care of it.","TWN":"現在距離我請求殿下待在營帳裡，讓我來處理這件事，也才過去了不到5分鐘。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흥. 이 녀석에게 예법으로 지키라는 거냐.","JPN":"ふん、こいつ相手に礼法を守れといういうのか。","ENG":"Hmph. You expect him to act with decorum?","TWN":"哼，我從不期望一個平民舉止得體。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"새 친구들까지 사귄 걸 보니 꽤 즐거운 산책이었나 보군.","JPN":"初めて見る顔ぶれまで連れてくるとは、相当楽しい散歩だったようだな。","ENG":"It must have been a fun little walk, seeing that you've made new friends already.","TWN":"你還交了新朋友，看來閒逛得很開心啊。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 근방의 도시에서 만났습니다.","JPN":"はい。近辺の街で遭遇しました。","ENG":"Yes, I ran into them in a nearby city.","TWN":"是的，他們是我在附近的城市遇到的。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하, 외람된 말씀이오나 저들의 정체를 확신하기에는 아직 이릅니다.","JPN":"殿下、恐れ入りますが、あの者たちの正体はまだ確信できません。","ENG":"Forgive me, Your Highness. I believe that these so-called \\"friends\\" are not to be trusted yet.","TWN":"殿下，恕我冒昧，現在確定他們的真實身份還為時過早。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마왕의 끄나풀일지도 모릅니다. 성녀를 불러 판별해 보시죠.","JPN":"魔王の手先かもしれません。聖女を呼んで確かめましょう。","ENG":"Perhaps they were sent by the Demon Lord. I request to call over the Saintess and identify them.","TWN":"他們說不定是魔王的爪牙，還是叫聖女來判別一下為好。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그럴 필요 없다, 알렌.","JPN":"その必要はない。アレン。","ENG":"There won't be any need for that, Allen.","TWN":"沒那個必要，艾倫。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕의 수하라면 평민이 먼저 알아챘겠지. 예법에는 무지해도 감각만큼은 예리하니 말이다.","JPN":"魔王の手下ならとっくにこの平民が気づいているだろう。礼法は知らなくても、勘だけは鋭いからな。","ENG":"If they belonged to the Demon Lord, the peasant would’ve noticed. Albeit his ignorance in etiquette, I believe his senses are trustworthy.","TWN":"是不是魔王的手下，平民會先認出來。雖然對禮法很無知，但敏銳的直覺還是具備的。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전투 중에 구원자의 감은 신뢰할 수 있습니다.","JPN":"戦闘中の救世主の勘は信頼できます。","ENG":"The Savior's instincts in battle can be trusted.","TWN":"戰鬥期間可以相信救贖者的直覺。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"평상시에는 못 미더운 구석뿐입니다만.","JPN":"普段はまったく頼り甲斐なんてありませんが。","ENG":"But not during everyday life.","TWN":"雖然平時不怎麼可靠。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안해, 샬롯. 고치려는데 잘 안 되더라.","JPN":"ごめんね、シャーロット。直す努力はしているんだけど。","ENG":"Sorry, Carlota. I'm trying to fix it, but it's not so easy.","TWN":"對不起，夏洛特。我想改的，但是改不好……"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래, 이 자들인가?","JPN":"ああ、この者たちか？","ENG":"So, they must be the friends we've been talking about.","TWN":"嗯，是這些人嗎？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"환영한다, 제국의 신민들이여.","JPN":"よくぞ来た、帝国の臣民たちよ。","ENG":"Welcome, subjects of the Empire.","TWN":"歡迎你們，帝國的百姓。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕의 점령지에서는 풀 한 포기 찾기 어려웠겠지?","JPN":"魔王の占領地では、食べる草すらもなかっただろう。","ENG":"I presume the Demon Lord's territory was not the most fertile.","TWN":"在寸草不生的魔王佔領區，很難品嘗到像樣的食物吧？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"따라와라. 마침 연회를 열어 병사들을 배불리 먹일 예정이었다.","JPN":"ついてこい。ちょうど宴会を開いて兵士たちをたらふく食べさせようとしていたところだ。","ENG":"Come. A feast for the soldiers is about to take place.","TWN":"來吧。為士兵們準備的宴會就要開始了。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"함께 어울리면서 그간의 피로를 마음껏 풀도록.","JPN":"共に参加して、溜まった疲労をよくほぐすが良い。","ENG":"Join us and rest your weary bodies.","TWN":"你們也一起加入，盡情消除一下這段時間累積的疲憊吧。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"분위기가…….","JPN":"ここの雰囲気は……","ENG":"The atmosphere here...","TWN":"氣氛……"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"많이 다르군요. 저희가 겪었던 것들과.","JPN":"大違いですね。僕たちが経験した出来事とは。","ENG":"It's drastically different from what we've gone through.","TWN":"很不一樣啊，和我們經歷過的相比。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"글쎄. 선배 말대로 환각의 일종이라면, 과거의 기억이라도 적당히 윤색되지 않았을까?","JPN":"さあね。先輩の言う通りこれも幻覚なら、過去の記憶とはいえ、都合よく美化されているんじゃないかしら？","ENG":"Hmm. If this really is a hallucination like you mentioned, maybe the memories were polished up a bit.","TWN":"這個嘛，如果真像你所說的那樣，這是一種幻覺，那過去的記憶也會被適當地美化吧？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"또 모르지. 우리 사기를 꺾기 위한 수작일 수도.","JPN":"そして、私たちの士気を下げるためにこういうふうに見せているのかもしれない。","ENG":"Or maybe it’s a strategy to lower our guards.","TWN":"也說不定，這只是讓我們放鬆警惕的手段。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그건……. 네 말처럼 그럴지도 모르지만……","JPN":"それは……確かにそうかもしれないけど……","ENG":"That's... You might be right, but...","TWN":"這個……或許你說的沒錯……"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배는 그럴 사람 같진 않았어.","JPN":"レイ先輩はそんな人には見えなかったよ。","ENG":"Ray didn't seem like someone who would do such a thing.","TWN":"但雷伊前輩不像那種人。"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금은 저 분들을 뒤따라가 보죠. 뭔가 더 확인할 수 있을지도 모르잖아요?","JPN":"今はあの方々について行ってみましょう。もっと何か確認できるかもしれませんから。","ENG":"For now, let's all follow him. We might get more information.","TWN":"現在先跟著他們去吧。說不定還能進一步確認一下呢？"},"stage":{"bg":"CAMP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"출정을 앞둔 마지막 날이다!","JPN":"今日は出征を控えた最後の日だ！","ENG":"Tomorrow is the day we leave for battle!","TWN":"今天是出征前的最後一天！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"구원자님과 황태자 전하, 성녀님까지 모두 한 자리에 모이셨다!","JPN":"救世主様と皇太子殿下、聖女様がこの場にいらっしゃる！","ENG":"The Savior, His Highness, and the Saintess have all come here to celebrate!","TWN":"救贖者大人，皇太子殿下，還有聖女全都來了！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"두려움은 잊어라! 오늘은 모두 배불리 먹고 즐기자!","JPN":"恐れる気持ちは忘れよ！　今日は皆、たらふく食べて楽しむんだ！","ENG":"Fear shall be forgotten! Tonight, we feast!","TWN":"忘記恐懼！今天大家盡情地吃飽享受吧！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래? 평민과 검을 겨뤘다고?","JPN":"そうか？　平民と剣を交えたと？","ENG":"Oh? You say you've fought against the peasant?","TWN":"是嗎？和平民比劍了？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L38_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"공격은 성공했나?","JPN":"攻撃は通用したか？","ENG":"Were any of your attacks effective?","TWN":"有打中嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아, 아니. 전부 막히긴 했는데…….","JPN":"い、いや。全部防がれちゃったけど……","ENG":"N-no. He blocked them all...","TWN":"沒，沒有，全被擋下了……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면 내 승리군.","JPN":"ならば私の勝ちだな。","ENG":"I am the victor here, then.","TWN":"那就是我贏了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"최근 대련에서 무려 옷깃을 베는 데 성공했으니까.","JPN":"最近の模擬対戦では、なんと襟元をかすめるのに成功したから。","ENG":"I succeeded in cutting off part of his sleeves in our last duel.","TWN":"在最近的對練中我成功地割破了他的衣領。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"호오, 흥미롭네요. 어떻게 해야 그런 대단한 위업을 세울 수 있는 거죠?","JPN":"へぇ……興味深いですね。どうすればそのような凄まじい偉業が成せるんですか？","ENG":"Oh, interesting. How did you achieve such greatness?","TWN":"哈哈，有意思。是怎麼完成如此偉大的壯舉的呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대처럼 죽어도 동료가 뒤를 맡아 줄 거라는 마음가짐으로 달려들면 된다. 그것뿐이야.","JPN":"狼のように、たとえ死んでも仲間が後を引き受けてくれるという気持ちで挑む、それだけだ。","ENG":"All it takes is trust. Trust that even if I die like the Wolf, my comrades will take care of the rest.","TWN":"像狼一樣，抱著哪怕自己死掉，同伴也會負責後方的信念撲上去就行了。僅此而已。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"구원자님에게도 그런 약점이 있었군요. 굉장한 정보네요.","JPN":"救世主様にもそのような弱点が。すごい情報ですね。","ENG":"I didn't know the mighty Savior had weaknesses... this is fascinating news.","TWN":"原來救贖者還有這樣的弱點。這個情報很了不得啊。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"……정보라기에는 영 시원치 않은데, 선배.","JPN":"……本当に使える情報なの？　先輩。","ENG":"...It's too trivial to be called news, Shiyoon.","TWN":"……說是情報，還不如說是瑣事呢，前輩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 서윤 양. 지금은 차분하게 지켜보세요.","JPN":"ハハ、まぁシズカさん、今は落ち着いて待ちましょう。","ENG":"Ha ha. Just watch for now, Seo Yoon.","TWN":"哈哈，先靜觀其變吧，徐芸小姐。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저쪽도 그걸 원한다면, 너무 조바심 낼 필요는 없지 않을까요?","JPN":"向こうも望んでいるものが同じなのであれば、あまり焦る必要はないでしょう？","ENG":"If it's what they want, there's no need to rush ourselves.","TWN":"如果這就是對方想要的，我們何必著急呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어떡할 거냐, 평민. 네가 지난번 대련에서 적당히 봐준 뒤로 샬롯이 줄곧 저 상태다.","JPN":"どうしてくれる、平民。貴様がこの前の模擬対戦で手を抜いてからというもの、シャーロットがずっとあの調子だ。","ENG":"What will you do now, peasant? Carlota has been like that ever since you've gone easy on her.","TWN":"你要如何應對呢，平民。自從上次你在對練中手下留情後，夏洛特就是那個樣子了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"제가 누굴 봐준다거나 할 실력이 아니라는 건 전하께서도 아시잖아요.","JPN":"僕の実力が誰かに手を抜くことができるようなものじゃないこと、殿下もご存知ではないですか。","ENG":"You know I'm not good enough to go easy on others, Your Highness.","TWN":"我沒什麼實力對別人手下留情，殿下也知道不是嘛。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"샬롯 경이 노력한 만큼 성과를 얻은 거라고 생각합니다.","JPN":"シャーロットが努力した分、結果がついてきただけです。","ENG":"I like to think that Dame Carlota achieved this through her own efforts.","TWN":"我認為是夏洛特卿的努力取得了相應的成果。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원자가 된 뒤로 입담만 늘었군. 내 앞에서 겸손 따위 떨지 마라.","JPN":"救世主になってから、口ばかり達者になったものだ。私の前で謙遜など必要ない。","ENG":"You've become quite cunning after earning the title of \\"Savior\\". Do not assume that you can fool me too.","TWN":"哼，成為救贖者以後，你的口才倒是長進了不少。少在我面前自謙。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 구원자님과 겨뤘다면 실력은 증명이 된 셈 아닌가요?","JPN":"ですが、救世主様とやり合ったのなら、すでに実力は証明されたのでは？","ENG":"But hasn’t she proved her worth by going against the Savior?","TWN":"如果和救贖者大人比試過了，不就相當於是證明實力了嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"마왕과의 전투에서 어지간한 실력자들은 방해만 될 뿐이겠죠.","JPN":"魔王との戦いでは、よっぽどの実力者でない限り、足手まといになるだけです。","ENG":"Any other mediocre swordsman wouldn't stand a chance against the Demon Lord.","TWN":"在與魔王的戰鬥中，實力一般的人只會礙事罷了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이대로 기사단에 합류시키는 건 어떨까요?","JPN":"このまま騎士団に合流させてはいかがでしょうか？","ENG":"Why don't we make her join the Knights of Redemption?","TWN":"就這樣讓她加入騎士團怎麼樣？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하, 실력이라고? 그대가 할 소리는 아니지 않나?","JPN":"はは、実力だと？　貴様が言うことではないと思うが。","ENG":"Ha ha, her worth? That's not for you to say.","TWN":"哈哈，實力？這不是你該說的話吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님께 드린 말씀이었습니다.","JPN":"私は救世主様に申し上げています。","ENG":"I was talking to the Savior.","TWN":"我是在和救贖者大人說話。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하께서는 저 방탕한 축제에나 끼어 계시죠.","JPN":"殿下はあのお祭り騒ぎに参加された方がよろしいのでは？","ENG":"You should go ahead and enjoy that lousy feast, your dear Highness.","TWN":"您現在不是應該在那個縱情享樂的慶典上嗎，殿下？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"술도 없는 자리에 끼어서 무엇하겠나. 병사들 음식만 축낼 뿐이지.","JPN":"酒もないところに参加してどうする。兵士たちの分の料理を減らしてしまうだけだ。","ENG":"What would one do without a drink to enjoy? All I can do there is take away the soldier’s food.","TWN":"沒有酒的宴會？還是把食物讓給士兵們好了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저기…… 전하.","JPN":"あの……殿下？","ENG":"Excuse me... Your Highness.","TWN":"那個……殿下。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저번에 여쭤 봤던 용병단 소식은 혹시 들어왔습니까?","JPN":"以前お伺いした傭兵隊に関してですが、何か情報は入ってきましたか？","ENG":"Any news from the Mercenaries I asked before?","TWN":"上次我問您的傭兵隊有消息了嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나를 전령 취급하는 녀석은 네가 유일할 거다, 평민.","JPN":"私を伝令扱いするヤツは貴様だけだ、平民。","ENG":"I believe that you are the only living soul to ever treat me as a messenger, peasant.","TWN":"你是唯一一個拿我當信使的人，平民。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"불편하셨다면 죄송합니다.","JPN":"お気に障ったら、申し訳ありません。","ENG":"Apologies if I made you uncomfortable.","TWN":"如果給您添麻煩了，那我很抱歉。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니. 됐다. 적당히 일러 두려고 했으니.","JPN":"いや、いい。どうせ話しておこうと思っていた。","ENG":"Keep your apologies. I was meaning to inform you anyway.","TWN":"不，算了，我本來就想找個適當的時機提醒你。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"결론부터 말해 주지. 펜릴 용병단은 포기해라.","JPN":"結論から言おう。フェンリル傭兵隊は諦めろ。","ENG":"Let me get straight to the point. Give up Fenrir Mercenaries.","TWN":"先說結論吧，放棄芬里爾傭兵隊吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네? 어째서죠?","JPN":"はい？　どうしてですか？","ENG":"What? How so?","TWN":"什麼？為什麼？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"우리 측 병사들이 거점에 찾아갔을 때는 전부 떠나 버린 뒤였어.","JPN":"我々の兵士たちが拠点にたどり着いたときには、すでに全員いなくなっていた。","ENG":"By the time our soldiers reached their base, they were already gone.","TWN":"我方士兵找到據點的時候，她們已經全部離開了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……우두머리였던 <color=#ffd34c>늑대</color>가 죽었으니까.","JPN":"……親玉だった<color=#ffd34c>狼</color>が死んでしまったからな。","ENG":"...Because their leader, the <color=#ffd34c>Wolf</color>, had passed.","TWN":"……因為曾經是首領的<color=#ffd34c>狼</color>死了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"단원들의 행적을 점령지까지 샅샅이 찾아 봤다만, 그 날의 전투 이후로 단원들의 행방이 묘연해졌다더군.","JPN":"団員たちの痕跡を占領地に至るまで隈なく探したということだが、あの日の戦闘以来、消息がつかめないらしい。","ENG":"We went through every single territory they conquered, but none of the members were to be found after the day of the battle.","TWN":"我們仔細追查了團員們的行蹤，直到佔領區。似乎是在那天的戰鬥之後，團員們就全都失去了蹤跡。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"결전을 앞두고 아쉬운 소식이군요. 함께 싸웠다면 큰 힘이 되었을 텐데요.","JPN":"決戦を前にして残念な知らせですね。一緒に戦えれば大きな戦力になっていたでしょうに。","ENG":"This is grave news. It would have been of great help if they were able to fight alongside us.","TWN":"決戰在即，這個消息可真讓人遺憾啊。如果她們也能一起作戰，應該會成為一大助力。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런 인재들이 황실의 명에 따르지 않고 멋대로 굴었으니 문제라는 거다.","JPN":"そのような粒ぞろいの集団が皇室の命令を無視して、自分勝手に振る舞ったことが問題なのだ。","ENG":"The problem is that the talents like them were acting on their own, disobeying the royal orders.","TWN":"那樣的人才不服從皇室的命令，任意妄為，這才是問題。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"애석하지만 제국에는 더 이상 전쟁을 지속할 여력이 없어.","JPN":"残念だが、帝国はもはや戦争を続ける余力がない。","ENG":"Grave as it is, the Empire is no longer capable of continuing war.","TWN":"可惜的是帝國已經沒有繼續戰爭的餘力了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그들이 있든 없든, 여기서 마왕을 패퇴시켜야 한다.","JPN":"彼らがいようがいまいが、ここで魔王とは決着をつけねばならない。","ENG":"Whether they come with us or not, we need to take down the Demon Lord here.","TWN":"不管有沒有她們，我們都必須在這裡打敗魔王。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 골짜기를 통과하면 수도까지는 거칠 것이 없을 테니까.","JPN":"この谷を抜け出れば、首都までは直通だ。","ENG":"After this creek, there won't be any obstacles until we reach the capital.","TWN":"越過這個山谷後，在到達首都之前應該都不會有麻煩了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"역시……. 그 때 혼자서 싸우러 가게 내버려 두면 안 됐는데……","JPN":"やっぱり……あの時一人で戦いに行かせるんじゃなかった……","ENG":"I knew it... I shouldn't have left her to fight alone...","TWN":"果然……當時就不該讓她一個人去戰鬥……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"쓸데없는 자책 하지 마라. 그건 늑대의 결정이었다.","JPN":"今更無駄な自責はやめろ。あれは狼自身が決めたことだ。","ENG":"It’s useless to blame yourself. It was the Wolf's decision to make.","TWN":"別做無謂的自責了，那是狼的決定。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"눈앞의 싸움에나 집중하도록. 내키지 않으면 황명이라도 내려 주지.","JPN":"目の前の戦いに集中しろ。それが難しいようなら勅令を出す。","ENG":"Focus on what's in front of you. I shall give a royal order if you don't feel like doing so.","TWN":"專注眼前的戰鬥。如果你不願意，我就要命令你了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇지만 전하, 늑대는 저와 구원자에게 스승이나……","JPN":"ですが殿下、狼は私や救世主にとっては師匠ともいうべき……","ENG":"But Your Highness, the Wolf was like a master to me as well as the Savi–","TWN":"但是，殿下，狼對我和救贖者來說是師父般的……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알겠습니다, 전하.","JPN":"承知しました、殿下。","ENG":"Very well, Your Highness.","TWN":"好的，殿下。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자?","JPN":"救世主？","ENG":"Savior?","TWN":"救贖者？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이번에는 저도 전하처럼 선봉에서 누구보다 열심히 싸우겠어요.","JPN":"今回は、僕も殿下のように先鋒に立って誰よりも戦いに注力します。","ENG":"I will fight with everything I have in the front lines, just like you did.","TWN":"這次我也要像殿下一樣，做個比任何人都更努力戰鬥的先鋒。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아무도 죽지 않게 할 겁니다. 늑대가 그랬던 것처럼요.","JPN":"誰も死なせやしません。狼のようには。","ENG":"I won't let any man die. Just like the Wolf did.","TWN":"我不會讓任何人死的，就像狼過去做的那樣。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하하! 당돌한 소리를 지껄이는군!","JPN":"ハハハッ！　大胆なことを言う！","ENG":"Ha ha ha! Such arrogance, I would say.","TWN":"哈哈哈！很莽撞的發言啊！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 썩 나쁘지 않아. 그 정도 배짱은 있어야 제국의 총기사단장직에 걸맞지.","JPN":"しかしその気概は悪くはない。それでこそ帝国の総騎士団長というものだ。","ENG":"But not bad at all. That's what I require from the Supreme Commander of the Empire's knights.","TWN":"還不錯。有這樣的膽量，才配得上帝國總騎士團長一職。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"총기사단장이요?","JPN":"総騎士団長ですって？","ENG":"The Commander?","TWN":"總騎士團長？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"칙명으로만 임명되는 특별한 직위다. 제국 역사를 통틀어 세 명뿐이었어.","JPN":"勅命によってのみ与えることができる特別な職位だ。帝国史上これまで三人しかいない。","ENG":"It's a special status given by royal decree only. Three people have been granted the title throughout the history of this Empire.","TWN":"這是僅通過敕命任命的特別職位。整個帝國歷史上也只有三位。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 그 자리는 전하께서 노리시던 것 아니었습니까?","JPN":"しかし、殿下がそれを目指されていたのでは？","ENG":"But isn't that a title you wanted, Your Highness?","TWN":"但這不是殿下一直想要的位置嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물론 몇 년 전까지는 그랬지.","JPN":"ああ、数年前まではな。","ENG":"A few years back, yes.","TWN":"幾年前確實如此。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 나는 황태자로서 나라를 이끌 몸이 아니던가?","JPN":"だが、私は皇太子として国を率いる存在だ。","ENG":"However, I am the crown prince who is to lead this Empire.","TWN":"不過身為皇太子，肩負著領導國家之重任。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전쟁이 끝났다고 구원자를 변방 시골로 돌아가게 내버려 두면 온 세상이 비웃을 거다.","JPN":"戦争が終わったからといって、救世主を辺境の田舎の地に帰らせるようでは、世界中から笑われるだろう。","ENG":"The whole world will mock me if I send off the Savior to a backwater village after the war is over.","TWN":"如果戰爭結束後，這麼任由救贖者解甲歸田，全王國的人都會嘲笑我的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국 구원자님을 이용하겠다는 것 아닙니까?","JPN":"結局救世主様を利用する、ということですよね？","ENG":"So you're just using him?","TWN":"說到底不就是想利用救贖者大人嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"심보가 고약하시군요, 전하.","JPN":"人が悪いですよ、殿下。","ENG":"How malevolent of you, Your Highness.","TWN":"城府很深呢，殿下。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"언동에 주의해 주십시오, 루크레시아. 성녀라고 목이 안 날아가는 건 아닙니다.","JPN":"言葉を慎まれよ、ルクレシア。聖女といえど、処刑の対象にならないわけではない。","ENG":"Choose your words wisely, Lucrecia. Your title of \\"Saintess\\" will not save you from getting sentenced to death.","TWN":"注意你的言辭，露可蕾西亞。聖女並不代表不會掉腦袋。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"윽……! 내가 아직도 그런 협박에 겁먹을 것 같아?","JPN":"くっ……！　私がまだそんな脅しに怖気づくとでも？","ENG":"Ugh...! You think your threats still work against me?","TWN":"呃……！你覺得我現在還會怕這種威脅嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"협박으로 끝날 것 같습니까?","JPN":"脅しで済むと思われるか？","ENG":"Do you think this is a mere threat?","TWN":"你認為這僅僅是威脅嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이…… 이래서 귀족들이란!","JPN":"こ……これだから貴族は！","ENG":"I... I hate aristocrats!","TWN":"所……所以我才痛恨你們這些貴族！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하, 그대에게 정치에 신경을 쓸 겨를이 있었나?","JPN":"ハハ、貴様に政治を気にする余力などあったのか？","ENG":"Ha ha, I know you don't have time to think about politics.","TWN":"哈哈，你還有時間關注政治？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알고 있겠다만, 성녀의 혼인은 교리로 금지하고 있다.","JPN":"知っていると思うが、聖女の婚姻は教義によって禁じられている。","ENG":"As you know, marriage is forbidden for Saints.","TWN":"你應該知道吧，教義是禁止聖女結婚的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그, 그건 갑자기 무슨 말씀입니까?","JPN":"そ、それはいきなりどういう意味でしょうか？","ENG":"I-I don't know what you're talking about.","TWN":"你，你突然說這個做什麼？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그깟 무의미한 신경전보다 더 중요한 데 집중하란 뜻이다.","JPN":"そのような無意味な心理戦を繰り広げるよりも、重要なことに集中しろということだ。","ENG":"What I am telling you is to focus on what's important, instead of getting involved in irrelevant feuds.","TWN":"我的意思是，比起那種毫無意義的心理戰，你應該專注於更重要的事。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대의 알량한 소원을 성취하고 싶다면 말이다.","JPN":"貴様のそのちっぽけな夢を叶えたかったらな。","ENG":"If you want your pathetic little wish to come true, that is.","TWN":"要想實現你那不怎麼樣的願望的話。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"큭…….","JPN":"クッ……","ENG":"Kgh…","TWN":"呃……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아, 결혼할 사람이 있었어?","JPN":"ルクレシア、結婚する相手がいたの？","ENG":"Oh, I didn't know you have a fiance, Lucrecia.","TWN":"露可蕾西亞，你有要結婚的人嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아닙니다! 절대로 아니에요!","JPN":"いいえ！　決してそのようなことはありません！","ENG":"No! Not at all!","TWN":"沒有！絕對沒有！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그래?","JPN":"そう？","ENG":"Oh, you don't?","TWN":"是嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"다행이다. 루크레시아는 이제 모두에게 사랑 받는 성녀잖아.","JPN":"よかった。ルクレシアはもうみんなの聖女だからね。","ENG":"That's a relief. You are the Saintess that everyone loves.","TWN":"那就好。露可蕾西亞如今可是深受所有人愛戴的聖女。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"성녀직에서 내려온다고 하면 다들 아쉬워할 거야.","JPN":"聖女をやめたら、みんな悲しがると思うよ。","ENG":"People would be sad if they see you stepping down from the title.","TWN":"如果你說要辭去聖女一職，大家都會覺得可惜的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨, 구원자님. 제 말은…….","JPN":"いいえ、救世主様。私は……","ENG":"No, Savior, that's not what I meant...","TWN":"不是，救贖者大人。我的意思是……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"얘기가 많이 돌아왔지만, 결국 생존자들의 처우는 그들 자신이 정해야겠지.","JPN":"話がだいぶ逸れてしまったが、結局生き延びた者は自らの境遇を決めねばならない。","ENG":"This conversation deviated to an excessive extent, but my conclusion is that the survivors will need to look after themselves.","TWN":"雖然說了很多，但倖存者應該如何處理，最終還是該由他們自己決定。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대들은 어찌 하고 싶나?","JPN":"そなたらはどうしたいのだ？","ENG":"What is it that you wish?","TWN":"你們想怎麼樣？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕 네헤모트에게 복수하길 원하나? 아니면 여생만큼은 평화롭게 보내길 바라나?","JPN":"魔王ネヘモトへの復讐か？　それとも残りの人生は平和に過ごしたいか？","ENG":"Do you wish to take vengeance on Nehemoth, the Demon Lord? Or do you wish to live your remaining life in peace?","TWN":"想報復魔王貝赫莫特嗎？還是說希望平安地度過餘生？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자, 선택해라. 원한다면 센트럴 팰리스로 갈 수 있도록 병력을 붙여 주마.","JPN":"さぁ、選べ。望めばセントラルパレスへ行けるよう、兵士をつけてやる。","ENG":"Choose. If you want, I will provide you with troops to head towards the Central Palace.","TWN":"好了，做選擇吧。如果你們需要，我會派兵力送你們去聖特羅貝里斯。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대답은 여기 올 때부터 정해져 있었어.","JPN":"答えはここに来た時点で決まってた。","ENG":"The answer was set the minute we entered here.","TWN":"從我們來這裡的那一刻起，答案就已經註定了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"싸우겠어. 네헤모트와.","JPN":"戦うよ。ネヘモトと。","ENG":"We're going to fight. Against Nehemoth.","TWN":"我們要和貝赫莫特戰鬥。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저, 정말인가요?","JPN":"ほ、本当ですか？","ENG":"R-really?","TWN":"真，真的嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……놀랍군. 정예 병력 중에도 겁에 질린 나머지 마왕의 수하들과 두 번 싸우지 못하는 자들이 부지기수인데.","JPN":"……驚きだな。精鋭の兵士でも一度戦えば、恐怖のあまり魔王の手下とは二度と戦えないことが多いのに。","ENG":"...Impressive. Most wouldn't dare fight against the Demon Lord and his forces, not even the elite soldiers.","TWN":"……我很驚訝。即使在精銳兵力中，被嚇得不敢與魔王手下交戰的人也不計其數。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래야지. 우리에게서 내일을 앗아간 자가 아니더냐.","JPN":"よく言った。奴らは我々の未来を奪ったのだからな。","ENG":"Of course they would fight. It is the very one who took away our future.","TWN":"也難怪。那些人可是奪走了我們未來的不是嗎。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경, 그레이스가 남긴 무구를 저들에게 하사해도 괜찮겠나?","JPN":"アレン、グレースが残した武具をこの者らに与えようと思うがどうだ？","ENG":"Sir Allen, would you mind if I bestow them the Armament that Grace left behind?","TWN":"艾倫卿，我把葛瑞絲留下的武器賜給他們可以嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"예, 전하. 그녀도 그렇게 해 주길 바랄 겁니다.","JPN":"はい、殿下。きっと彼女もそれを望んでいると思います。","ENG":"Not at all, Your Highness. Grace would have wanted the same.","TWN":"是的，殿下。她也會希望您這樣做的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋다. 내일 아침 출정식이 열릴 예정이니 그대들도 참석하도록.","JPN":"決まりだな。明日の朝は出征式だ。そなたらも参席せよ。","ENG":"Good. The celebration of war starts tomorrow morning. You are all required to attend.","TWN":"好。那麼明天早晨舉行的出征儀式，你們也參加吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"유미나, 갑자기 왜 그런 쓸데없는 말을 꺼내?","JPN":"ミナ、いきなりどうしてあんなことを言ったの？","ENG":"Yoo Mina, why would you say such a thing?","TWN":"……米娜，你幹嘛突然說那些廢話啊？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이건 지금 현실 같은 환각이야. 여기서 다치면 현실에도 영향이 갈 수 있다고.","JPN":"今のこれは現実に限りなく近い幻覚よ。ここで怪我をすれば現実にも影響があるかもしれないわ。","ENG":"The hallucination we're in is very much real. If we get hurt here, it might affect us in reality.","TWN":"如果這裡是像現實一樣逼真的幻覺。那麼受傷的話，對現實可能也會有影響。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕이란 존재에 대해 알 수 있는 기회잖아.","JPN":"魔王がどんなものかを知るいいチャンスだよ。","ENG":"Because this is a good opportunity to find out more about the Demon Lord.","TWN":"可是，這是個了解魔王這種存在的機會不是嘛。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"적에 대해 파악하는 건 용병으로서 당연히 해야 할 일 아냐?","JPN":"敵について把握することは、傭兵として当然じゃない？","ENG":"Isn't it our job as mercenaries to analyze the enemy?","TWN":"了解敵人，不是身為傭兵應該做的事嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그 때처럼……","JPN":"あの時のように……","ENG":"Just like then...","TWN":"就像那時那樣……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"리플레이서 비숍 때처럼, 레이 선배란 사람에게 아직 미련이 남아 있는 게 아니라?","JPN":"リプレイサー・ビショップの時のように、レイ先輩という人にまだ未練があるんじゃなくて？","ENG":"Aren't you still hung up on Ray, just like that time with Replacer Bishop?","TWN":"你不是像克隆·大主教那時那樣，還對雷伊前輩這個人懷有留戀吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"네 심정은 알겠어.","JPN":"あなたの気持ちはわかる。","ENG":"I understand how you feel.","TWN":"我理解你的心情。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그렇지만 이번에는 리플레이서 때와 경우가 달라. 그건 잊지 마.","JPN":"でも今回はリプレイサーのときとは訳が違うの。それを忘れないで。","ENG":"But this is different from back then. Don't forget that.","TWN":"不過這次和克隆集團那時的情況不一樣。這一點你別忘了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……그런 건 나도 알고 있어.","JPN":"……そんなのわかってるよ。","ENG":"...I know that already.","TWN":"……我也知道這些。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배도 내가 괜한 선택을 했다고 생각해?","JPN":"先輩も私が余計な選択をしたと思う？","ENG":"Do you also think I made a bad decision, Shiyoon?","TWN":"前輩也覺得我做了不該做的選擇嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 모든 사람이 만족하는 선택은 도시전설 같은 거예요, 미나 양.","JPN":"ハハ、全員が満足できる選択なんて、夢物語のようなものなんですよ、ミナさん。","ENG":"Ha ha, you know you can't please everyone, Mina.","TWN":"哈哈，怎麼可能會有讓所有人都滿意的選擇呢，米娜。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저는 서윤 양과 다르게 조금 궁금하긴 하던데요?","JPN":"僕はシズカさんとは違って、少し知りたくはなりましたよ？","ENG":"I do have to admit that I'm curious, unlike Seo Yoon.","TWN":"我和徐芸不同，我有一點好奇呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"왜 저 사람들이 세상을 멸망시키려고 그렇게 애를 썼는지 말입니다.","JPN":"なんであの人たちが、あれほど世界を滅亡させようと必死だったのか。","ENG":"I want to know why they tried so hard to put an end to the world.","TWN":"為什麼那些人會煞費苦心地想要毀滅我們的世界。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응. 나도 같은 생각이야.","JPN":"うん、私も同じ考え。","ENG":"Same here.","TWN":"嗯，我也是這麼想的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"혹시나, 만에 하나지만 여기서 답을 찾는다면…….","JPN":"もし、万が一だけど、ここでその答えを見つけることができれば……","ENG":"If, and I mean IF we find the answer here...","TWN":"萬一，萬一能在這裡找到答案……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배를 멈출 기회는… 아직 남아 있다고 생각해.","JPN":"レイ先輩を止めるチャンスは……まだ残っていると思うんだ。","ENG":"I think there is still a chance... that we might be able to stop Ray.","TWN":"我認為……還有機會阻止雷伊前輩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};